// ProductCard receives everything it displays as props.
// It cannot and does not need to remember anything.
function ProductCard({ name, price, imageUrl, onAddToCart }) {
  return (
    <div className="card">
      <img src={imageUrl} alt={name} />
      <h3>{name}</h3>
      <p>${price.toFixed(2)}</p>
      <button onClick={onAddToCart}>Add to cart</button>
    </div>
  );
}

// Parent controls all the data:
<ProductCard
  name="Mechanical Keyboard"
  price={129.99}
  imageUrl="/img/keyboard.jpg"
  onAddToCart={() => addItem(product)}
/>

import { useState } from 'react';

// Accordion manages its own open/closed state.
// The parent doesn't need to know or care.
function Accordion({ title, children }) {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="accordion">
      <button
        onClick={() => setIsOpen(o => !o)}
        aria-expanded={isOpen}
      >
        {title}
        <span>{isOpen ? '▲' : '▼'}</span>
      </button>
      {isOpen && <div>{children}</div>}
    </div>
  );
}

// The caller never touches isOpen:
<Accordion title="What is React?">
  <p>React is a JavaScript library for building user interfaces.</p>
</Accordion>

function LikeButton({ postId, initialCount }) {
  //                  ^^^^^^  ^^^^^^^^^^^^^
  //            props ──────────────────── from outside

  const [count, setCount] = useState(initialCount);  // state — owned inside
  const [liked,  setLiked]  = useState(false);        // state — owned inside

  function handleLike() {
    if (!liked) {
      setCount(c => c + 1);
      setLiked(true);
      // postId comes from props — used here to tell the API which post
      api.likePost(postId);
    }
  }

  return (
    <button
      onClick={handleLike}
      aria-pressed={liked}
      className={liked ? 'liked' : ''}
    >
      ♥ {count}
    </button>
  );
}

// ❌ Anti-pattern: storing derived data in state
function CartSummary({ items }) {
  const [total, setTotal] = useState(0);

  // This effect tries to keep total in sync — unnecessarily complex:
  useEffect(() => {
    setTotal(items.reduce((sum, i) => sum + i.price * i.qty, 0));
  }, [items]);

  return <p>Total: ${total.toFixed(2)}</p>;
}

// ✓ Correct: compute during render — no state, no effect
function CartSummary({ items }) {
  const total = items.reduce((sum, i) => sum + i.price * i.qty, 0);
  return <p>Total: ${total.toFixed(2)}</p>;
}

// ✓ Also correct: expensive computation memoised
function CartSummary({ items }) {
  const total = useMemo(
    () => items.reduce((sum, i) => sum + i.price * i.qty, 0),
    [items]
  );
  return <p>Total: ${total.toFixed(2)}</p>;
}

// EditableTitle starts from the server-provided title but can be edited locally
function EditableTitle({ initialTitle }) {
  const [title, setTitle] = useState(initialTitle);  // seeded from prop, then local

  return (
    <input
      value={title}
      onChange={e => setTitle(e.target.value)}
    />
  );
}

// If the parent later passes a different initialTitle,
// the input WON'T update — state was only seeded once.
// To handle that, you'd need to use a key:
<EditableTitle key={postId} initialTitle={post.title} />
// A new key unmounts/remounts the component, seeding fresh state.

// Alternative: use useEffect to sync (complex, usually avoidable)
// Alternative: make it fully controlled (no local state)

// Controlled: value is a prop — parent owns the state
function ControlledInput({ value, onChange }) {
  return <input value={value} onChange={onChange} />;
}

// Usage: parent tracks the value
function Parent() {
  const [text, setText] = useState('');
  return <ControlledInput value={text} onChange={e => setText(e.target.value)} />;
}

// Uncontrolled: value is internal state — component owns it
function UncontrolledInput({ defaultValue = '' }) {
  // DOM manages the value; we only seed it with defaultValue
  return <input defaultValue={defaultValue} />;
  // To read the value: use a ref
}

function Counter({ label }) {
  const [count, setCount] = useState(0);
  return (
    <div>
      <p>{label}: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
    </div>
  );
}

// Two separate instances, two separate states:
<Counter label="A" />   // has its own count: 0
<Counter label="B" />   // has its own count: 0

// Clicking A's button only changes A's count.
// B is unaffected.

import { render, screen, fireEvent } from '@testing-library/react';
import LikeButton from './LikeButton';

// 1. Test prop-driven rendering
test('displays initial count from prop', () => {
  render(<LikeButton postId="1" initialCount={42} />);
  expect(screen.getByRole('button')).toHaveTextContent('42');
});

// 2. Test state transition (user interaction)
test('increments count when clicked', async () => {
  render(<LikeButton postId="1" initialCount={10} />);
  const button = screen.getByRole('button');
  fireEvent.click(button);
  expect(button).toHaveTextContent('11');  // state changed
  expect(button).toHaveAttribute('aria-pressed', 'true');
});

// 3. Test that state is isolated per instance
test('two instances have independent state', () => {
  const { getAllByRole } = render(
    <>
      <LikeButton postId="1" initialCount={0} />
      <LikeButton postId="2" initialCount={0} />
    </>
  );
  const [btn1, btn2] = getAllByRole('button');
  fireEvent.click(btn1);
  expect(btn1).toHaveTextContent('1');
  expect(btn2).toHaveTextContent('0');  // unaffected
});

import { useState } from 'react';

// Props have an explicit type — visible to callers
type LikeButtonProps = {
  postId: string;
  initialCount: number;
  onLike?: (postId: string) => void;  // optional callback
};

function LikeButton({ postId, initialCount, onLike }: LikeButtonProps) {
  // State types are inferred from initial value:
  const [count, setCount] = useState(initialCount); // inferred: number
  const [liked, setLiked]  = useState(false);        // inferred: boolean

  function handleLike() {
    if (liked) return;
    setCount(c => c + 1);
    setLiked(true);
    onLike?.(postId);
  }

  return (
    <button onClick={handleLike} aria-pressed={liked}>
      ♥ {count}
    </button>
  );
}

// App owns the state
function App() {
  const [user, setUser] = useState<User | null>(null);
  return <Dashboard user={user} />;
}

// Dashboard doesn't need user itself — just passes it down
function Dashboard({ user }: { user: User | null }) {
  return <Sidebar user={user} />;
}

// Sidebar also doesn't need user — passes it further
function Sidebar({ user }: { user: User | null }) {
  return <UserAvatar user={user} />;
}

// UserAvatar finally uses it
function UserAvatar({ user }: { user: User | null }) {
  if (!user) return <span>Guest</span>;
  return <img src={user.avatarUrl} alt={user.name} />;
}

// BEFORE: each component owns its own tab state — they can't sync
function TabA() {
  const [active, setActive] = useState(false);
  // ...
}
function TabB() {
  const [active, setActive] = useState(false);
  // ...
}

// AFTER: lift state to the parent so siblings share it
function TabGroup() {
  const [activeTab, setActiveTab] = useState<'a' | 'b'>('a');
  return (
    <>
      <TabA isActive={activeTab === 'a'} onActivate={() => setActiveTab('a')} />
      <TabB isActive={activeTab === 'b'} onActivate={() => setActiveTab('b')} />
    </>
  );
}

function TabA({ isActive, onActivate }: { isActive: boolean; onActivate: () => void }) {
  return <button onClick={onActivate} className={isActive ? 'active' : ''}>Tab A</button>;
}

function Parent() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <button onClick={() => setCount(c => c + 1)}>Increment</button>
      {/* Every click → state changes → Parent re-renders → Child gets new prop */}
      <Child value={count} />
    </div>
  );
}

function Child({ value }: { value: number }) {
  // Always receives the latest count — no sync needed
  return <p>Count is: {value}</p>;
}
